#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define N 1024
#define T 100

int main() {
    float *a = (float*)malloc(N * sizeof(float));
    float *b = (float*)malloc(N * sizeof(float));

    // Initialize arrays
    for (int i = 0; i < N; i++) {
        a[i] = i;
        b[i] = 0;
    }

    for (int t = 0; t < T; t++) {
        #pragma omp parallel for
        for (int i = 1; i < N - 1; i++) {
            b[i] = (a[i - 1] + a[i] + a[i + 1]) / 3.0f;
        }
        #pragma omp parallel for
        for (int i = 1; i < N - 1; i++) {
            a[i] = b[i];
        }
    }

    // Print result
    for (int i = 0; i < N; i++) {
        printf("%f\n", a[i]);
    }

    free(a);
    free(b);
    return 0;
}
